def _veg_share(model, mm):
    return sum(model.use[mm, pp] for pp in model.pv) <= 0.40 * model.produce[mm]
model.veg_share = Constraint(model.m, rule=_veg_share)

def _cap_o2(model, mm):
    return model.use[mm, 'o2'] <= 150
model.cap_o2_each = Constraint(model.m, rule=_cap_o2)

def _o3_share(model, mm):
    return model.use[mm, 'o3'] <= 0.30 * (model.use[mm, 'o2'] + model.use[mm, 'o3'])
model.o3_share = Constraint(model.m, rule=_o3_share)
